Certainly! Setting up a robust infrastructure using Terraform involves organizing your code into modules that are reusable and maintainable. Below is an example of how you might structure your Terraform project for AWS networking, EKS (Elastic Kubernetes Service), and shared security controls.

### Project Structure

```
terraform-aws-platform/
├── main.tf
├── variables.tf
├── outputs.tf
└── modules/
    ├── vpc/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    ├── eks/
    │   ├── main.tf
    │   ├── variables.tf
    │   └── outputs.tf
    └── security/
        ├── main.tf
        ├── variables.tf
        └── outputs.tf
```

### Main Configuration Files

#### `main.tf`
This file will reference the modules and define any top-level resources or configurations that span multiple modules.

```hcl
provider "aws" {
  region = var.aws_region
}

module "vpc" {
  source            = "./modules/vpc"
  cidr_block        = var.vpc_cidr_block
  az_count          = var.az_count
  public_subnets   = var.public_subnets
  private_subnets  = var.private_subnets
  nat_gateway       = true
}

module "eks" {
  source            = "./modules/eks"
  vpc_id            = module.vpc.vpc_id
  subnet_ids        = module.vpc.public_subnet_ids
  cluster_name      = var.eks_cluster_name
  node_group_names = ["ng-public"]
  node_instance_types = ["t3.medium"]
}

module "security" {
  source            = "./modules/security"
  vpc_id            = module.vpc.vpc_id
}
```

#### `variables.tf`
This file will define the variables used in your Terraform configuration.

```hcl
variable "aws_region" {
  description = "The AWS region to deploy resources."
}

variable "vpc_cidr_block" {
  description = "CIDR block for the VPC."
}

variable "az_count" {
  description = "Number of availability zones to use."
}

variable "public_subnets" {
  description = "List of public subnets per AZ."
}

variable "private_subnets" {
  description = "List of private subnets per AZ."
}

variable "eks_cluster_name" {
  description = "Name for the EKS cluster."
}
```

#### `outputs.tf`
This file will define any outputs that you want to expose from your Terraform configuration.

```hcl
output "vpc_id" {
  value = module.vpc.vpc_id
}

output "eks_cluster_name" {
  value = module.eks.cluster_name
}
```

### Module Structure

#### VPC Module (`modules/vpc`)

##### `main.tf`
This file will define the resources for creating a VPC and subnets.

```hcl
resource "aws_vpc" "vpc" {
  cidr_block           = var.cidr_block
  enable_dns_hostnames = true
}

resource "aws_subnet" "public_subnets" {
  count             = length(var.public_subnets)
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = element(var.public_subnets, count.index)
  availability_zone = format("%s%s", var.region, ["a", "b", "c"][count.index])
}

resource "aws_subnet" "private_subnets" {
  count             = length(var.private_subnets)
  vpc_id            = aws_vpc.vpc.id
  cidr_block        = element(var.private_subnets, count.index)
  availability_zone = format("%s%s", var.region, ["a", "b", "c"][count.index])
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_nat_gateway" "nat_gateways" {
  count             = length(var.public_subnets)
  allocation_id     = data.aws_eip.nat[count.index].id
  subnet_id         = aws_subnet.public_subnets[count.index].id

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route_table" "public_routes" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route" "internet_gateway_route" {
  count             = length(var.public_subnets)
  route_table_id    = aws_route_table.public_routes[count.index].id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id        = aws_internet_gateway.igw.id
}

resource "aws_route_table_association" "public_subnet_assoc" {
  count             = length(var.public_subnets)
  subnet_id         = aws_subnet.public_subnets[count.index].id
  route_table_id    = aws_route_table.public_routes[count.index].id
}
```

##### `variables.tf`
This file will define the variables used in the VPC module.

```hcl
variable "cidr_block" {
  description = "CIDR block for the VPC."
}

variable "public_subnets" {
  description = "List of public subnets per AZ."
}

variable "private_subnets" {
  description = "List of private subnets per AZ."
}

variable "az_count" {
  description = "Number of availability zones to use."
}
```

##### `outputs.tf`
This file will define the outputs for the VPC module.

```hcl
output "vpc_id" {
  value = aws_vpc.vpc.id
}

output "public_subnet_ids" {
  value = aws_subnet.public_subnets.*.id
}

output "private_subnet_ids" {
  value = aws_subnet.private_subnets.*.id
}
```

#### EKS Module (`modules/eks`)

##### `main.tf`
This file will define the resources for creating an EKS cluster.

```hcl
resource "aws_eks_cluster" "cluster" {
  name                = var.cluster_name
  role_arn            = data.aws_iam_role.eks.arn
  vpc_config          = var.vpc_config
}

resource "aws_eks_node_group" "node_groups" {
  for_each         = toset(var.node_group_names)
  cluster_name     = aws_eks_cluster.cluster.name
  node_group_name = each.key
  node_role_arn   = data.aws_iam_role.eks_nodes.arn
  subnet_ids      = var.subnet_ids
  instance_types  = var.instance_types
}

data "aws_iam_policy_document" "assume_role_policy" {
  statement {
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["eks.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "eks" {
  name               = "${var.cluster_name}-role"
  assume_role_policy = data.aws_iam_policy_document.assume_role_policy.json
}

data "aws_iam_policy_document" "node_assume_role_policy" {
  statement {
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["ec2.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "eks_nodes" {
  name               = "${var.cluster_name}-nodes-role"
  assume_role_policy = data.aws_iam_policy_document.node_assume_role_policy.json
}
```

##### `variables.tf`
This file will define the variables used in the EKS module.

```hcl
variable "cluster_name" {
  description = "Name for the EKS cluster."
}

variable "vpc_config" {
  description = "VPC configuration for the EKS cluster."
}

variable "node_group_names" {
  description = "Names of node groups to create."
}

variable "subnet_ids" {
  description = "List of subnet IDs for the EKS nodes."
}

variable "instance_types" {
  description = "Instance types for the EKS nodes."
}
```

##### `outputs.tf`
This file will define the outputs for the EKS module.

```hcl
output "cluster_name" {
  value = aws_eks_cluster.cluster.name
}
```

#### Security Module (`modules/security`)

##### `main.tf`
This file will define security-related resources such as IAM policies, roles, and S3 buckets for storing Terraform state files securely.

```hcl
resource "aws_s3_bucket" "terraform_state" {
  bucket = "${var.vpc_id}-terraform-state"
}

resource "aws_iam_policy" "s3_access_policy" {
  name        = "s3-access-policy"
  path        = "/"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect   = "Allow",
        Action   = ["s3:Get*", "s3:Put*"],
        Resource = "${aws_s3_bucket.terraform_state.arn}/*"
      }
    ]
  })
}

resource "aws_iam_role" "terraform_state_access" {
  name               = "terraform-state-access-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect   = "Allow",
        Action   = ["sts:AssumeRole"],
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "s3_access_policy_attachment" {
  role       = aws_iam_role.terraform_state_access.name
  policy_arn = aws_iam_policy.s3_access_policy.arn
}
```

##### `variables.tf`
This file will define the variables used in the security module.

```hcl
variable "vpc_id" {
  description = "ID of the VPC."
}
```

##### `outputs.tf`
This file will define the outputs for the security module.

```hcl
output "s3_bucket_name" {
  value = aws_s3_bucket.terraform_state.bucket
}

output "iam_role_arn" {
  value = aws_iam_role.terraform_state_access.arn
}
```

### Summary

The above structure provides a modular and organized approach to setting up AWS infrastructure using Terraform. Each module handles specific aspects of the deployment, making it easier to manage and extend your configuration as needed.

- **VPC Module**: Handles VPC creation along with public/private subnets.
- **EKS Module**: Sets up an EKS cluster within the created VPC.
- **Security Module**: Manages security-related resources like IAM roles and S3 buckets for storing Terraform state files securely.

This structure ensures that your code is clean, maintainable, and easy to understand.

Handling remote state in Terraform is crucial for team collaboration and ensuring consistency across multiple environments. Using a centralized storage solution like AWS S3 is a common practice. Below are the steps to set up remote state management with S3, including locking mechanisms using DynamoDB.

### Remote State Setup

1. **S3 Bucket**: Store your Terraform state files in an S3 bucket.
2. **DynamoDB Table**: Use a DynamoDB table for locking to prevent concurrent modifications of the state file.

#### Step 1: Create S3 Bucket and IAM Role

First, create an S3 bucket specifically for storing Terraform state files:

```hcl
resource "aws_s3_bucket" "terraform_state" {
  bucket = "${var.vpc_id}-terraform-state"
}

# Ensure that your team members have the necessary permissions to access this bucket.
```

#### Step 2: Create DynamoDB Table

Create a DynamoDB table for locking purposes:

```hcl
resource "aws_dynamodb_table" "terraform_locks" {
  name           = "${var.vpc_id}-terraform-locks"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "LockID"
    type = "S"
  }

  hash_key       = "LockID"
}
```

#### Step 3: Configure Remote State in Terraform

Update your `main.tf` to configure the remote state and locking mechanism:

```hcl
terraform {
  backend "s3" {
    bucket         = aws_s3_bucket.terraform_state.bucket
    key            = "terraform.tfstate"
    region         = var.aws_region
    dynamodb_table = aws_dynamodb_table.terraform_locks.name
  }
}
```

